const raw = msg.payload;

// Cek field wajib dari firmware esp32_environment.ino
if (raw.rainfall === undefined || raw.rainfall === null) {
    node.warn('[ENV] Missing rainfall: ' + JSON.stringify(raw));
    return null;
}
if (raw.water_level === undefined || raw.water_level === null) {
    node.warn('[ENV] Missing water_level: ' + JSON.stringify(raw));
    return null;
}
if (isNaN(parseFloat(raw.rainfall)) || parseFloat(raw.rainfall) < 0) {
    node.warn('[ENV] rainfall tidak valid: ' + raw.rainfall);
    return null;
}
if (isNaN(parseFloat(raw.water_level)) || parseFloat(raw.water_level) < 0) {
    node.warn('[ENV] water_level tidak valid: ' + raw.water_level);
    return null;
}

return msg;

const raw = msg.payload;

// Cek token
const token = flow.get('IOT_JWT_TOKEN');
if (!token) {
    node.warn('[ENV] Token belum ada, payload masuk antrian.');
    const q = flow.get('pendingQueue') || [];
    q.push(raw);
    flow.set('pendingQueue', q);
    return null;
}

// Build payload — hanya field yang ada di firmware
msg.payload = {
    sensor_id   : String(raw.sensor_id || 'ESP32-ENV-01'),
    rainfall    : Math.round(parseFloat(raw.rainfall) * 100) / 100,
    water_level : Math.round(parseFloat(raw.water_level) * 100) / 100
};

msg.headers = {
    'Content-Type' : 'application/json',
    'Authorization': 'Bearer ' + token
};

msg.url = (env.get('API_GATEWAY_URL') || 'http://api-gateway:3000')
         + '/api/environment/sensor';

node.log('[ENV] sensor_id=' + msg.payload.sensor_id
    + ' rainfall='    + msg.payload.rainfall
    + ' water_level=' + msg.payload.water_level);

return msg;

const status = msg.statusCode;
const body   = msg.payload;

if (status === 201) {
    const d = body.data || {};
    node.log('[ENV OK] id=' + d.id
        + ' flood_status=' + d.flood_status
        + ' alerts_created=' + (d.alerts_created || 0));

} else if (status === 401) {
    node.warn('[ENV] Token expired — force refresh.');
    flow.set('iot_token_exp', 0);
    // Simpan payload ke antrian biar di-retry
    const q = flow.get('pendingQueue') || [];
    if (body) q.push(body);
    flow.set('pendingQueue', q);

} else if (status === 422) {
    node.warn('[ENV] Validasi gagal: ' + body.message);

} else if (status === 429) {
    node.warn('[ENV] Rate limit — masuk antrian.');
    const q = flow.get('pendingQueue') || [];
    if (body) q.push(body);
    flow.set('pendingQueue', q);

} else {
    node.error('[ENV ERROR ' + status + '] ' + JSON.stringify(body));
}

return msg;

const queue = flow.get('pendingQueue') || [];
if (queue.length === 0) return null;

const item = queue.shift();
flow.set('pendingQueue', queue);

const token = flow.get('IOT_JWT_TOKEN') || '';

msg.payload = {
    sensor_id   : String(item.sensor_id || 'ESP32-ENV-01'),
    rainfall    : parseFloat(item.rainfall  || 0),
    water_level : parseFloat(item.water_level || 0)
};
msg.url     = (env.get('API_GATEWAY_URL') || 'http://api-gateway:3000')
             + '/api/environment/sensor';
msg.headers = {
    'Content-Type' : 'application/json',
    'Authorization': 'Bearer ' + token
};

node.log('[ENV RETRY] remaining=' + queue.length);
return msg;

const exp = flow.get('iot_token_exp') || 0;
if (Date.now() < exp - 60000) {
    node.status({ fill: 'green', shape: 'dot', text: 'token valid' });
    return null;
}
node.status({ fill: 'yellow', shape: 'ring', text: 'refreshing...' });
return msg;

const authUrl = env.get('AUTH_SERVICE_URL') || 'http://auth-service:3002';
msg.url     = authUrl + '/oauth/token';
msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    grant_type   : 'client_credentials',
    client_id    : env.get('IOT_CLIENT_ID')     || 'iot-environment-device',
    client_secret: env.get('IOT_CLIENT_SECRET') || ''
};
return msg;

if (msg.statusCode === 200 && msg.payload && msg.payload.access_token) {
    flow.set('IOT_JWT_TOKEN', msg.payload.access_token);
    flow.set('iot_token_exp', Date.now() + (msg.payload.expires_in || 3600) * 1000);
    node.status({ fill: 'green', shape: 'dot', text: 'token refreshed' });
    node.log('[AUTH OK] IoT token refreshed');
} else {
    node.status({ fill: 'red', shape: 'ring', text: 'auth failed' });
    node.error('[AUTH FAILED] ' + JSON.stringify(msg.payload));
}
return null;
